from abc import ABC, abstractmethod
from dataclasses import dataclass
from enum import Enum
from typing import Dict, Optional, Tuple

from pyspark.sql.types import StructType


class TimerWriteBufferOperation(Enum):
    """
    Internal timer operation to be stored in the write buffer.
    """
    REGISTER = 1
    DELETE = 2


@dataclass
class ValueStateWriteBufferEntry:
    """
    Value state entry stored in the write buffer. It contains the pending values to be written
    back to the server.
    :param value: the value of the state.
    :type value: Tuple
    :param schema: the schema of the value state.
    :type schema: StructType
    """
    value: Tuple
    schema: StructType


@dataclass
class MapStateWriteBufferEntry:
    """
    Map state entry stored in the write buffer. It contains the pending user_key,value pairs
    to be written back to the server.
    :param user_key_value_pairs: the user_key,value pairs of the state. If the value is None,
    it means remove_key() was called on the corresponding user_key.
    :type user_key_value_pairs: Dict[Tuple, Optional[Tuple]]
    :param user_key_schema: the schema of the user_key in map state.
    :type schema: StructType
    :param value_schema: the schema of the value in map state.
    :type schema: StructType
    """
    user_key_value_pairs: Dict[Tuple, Optional[Tuple]]
    user_key_schema: StructType
    value_schema: StructType


@dataclass
class TimerWriteBufferEntry:
    """
    Timer entry stored in the write buffer. It contains the pending expiryTimestampMs to be
    registered or deleted on the server.
    :param expiryTimestampMs: the expiry timestamp in ms.
    :type expiryTimestampMs: int
    :param operation: the operation to be performed on the timer, either REGISTER or DELETE.
    :type operation: TimerWriteBufferOperation
    """
    expiryTimestampMs: int
    operation: TimerWriteBufferOperation


class StateIpcProcessor(ABC):
    # Read operations return Optional so that None signals the caller to fall back to
    # direct IPC, avoiding duplication of the base IPC code in the processor itself.
    # Write operations are always handled by the processor (void return).

    @property
    @abstractmethod
    def supports_ttl_state(self) -> bool: ...

    # Value state operations
    @abstractmethod
    def value_state_exists(self, state_name: str, schema: StructType) -> Optional[bool]: ...
    @abstractmethod
    def value_state_get(
        self, state_name: str, schema: StructType
    ) -> Optional[Tuple[Optional[Tuple], bool]]: ...
    @abstractmethod
    def value_state_update(self, state_name: str, value: Tuple, schema: StructType) -> None: ...
    @abstractmethod
    def value_state_clear(self, state_name: str) -> None: ...

    # Map state operations
    @abstractmethod
    def map_state_exists(self, state_name: str) -> Optional[bool]: ...
    @abstractmethod
    def map_state_get_value(
        self, state_name: str, user_key: Tuple,
        user_key_schema: StructType, value_schema: StructType,
    ) -> Optional[Tuple[Optional[Tuple], bool]]: ...
    @abstractmethod
    def map_state_contains_key(
        self, state_name: str, user_key: Tuple,
        user_key_schema: StructType,
    ) -> Optional[bool]: ...
    @abstractmethod
    def map_state_update_value(
        self, state_name: str, user_key: Tuple, value: Tuple,
        user_key_schema: StructType, value_schema: StructType,
    ) -> None: ...
    @abstractmethod
    def map_state_remove_key(
        self, state_name: str, key: Tuple,
        user_key_schema: StructType, value_schema: StructType,
    ) -> None: ...
    @abstractmethod
    def map_state_clear(self, state_name: str) -> None: ...

    # Timer operations
    @abstractmethod
    def buffer_timer(
        self, expiry_timestamp_ms: int, operation: TimerWriteBufferOperation
    ) -> None: ...

    # Lifecycle hooks
    @abstractmethod
    def on_new_grouping_key(self, key: Tuple) -> None:
        """Called before processing a new grouping key."""
        ...
    @abstractmethod
    def on_partition_close(self) -> None:
        """Called when the partition is being closed."""
        ...
    @abstractmethod
    def on_timers_complete(self) -> None:
        """Called after all expired timers have been processed."""
        ...
    @abstractmethod
    def on_iterator_start(self) -> None:
        """Called before a server-side iterator is created."""
        ...
